const jdNodes = $('Fetch Job Description').all();
const jd = jdNodes.length > 0 ? jdNodes[0].json : {};

// hr_assessments stores skills as Postgres text[] array e.g. {Node.js,PostgreSQL,Docker}
let skillsText = 'Programming';
try {
  if (Array.isArray(jd.skills)) {
    skillsText = jd.skills.join(', ');
  } else if (typeof jd.skills === 'string') {
    skillsText = jd.skills.replace(/[{}]/g, '');
  }
} catch(e) {}

// Include full JD if available for richer context
const jobDescContext = jd.job_description ? `\n\n**FULL JOB DESCRIPTION:**\n${jd.job_description}` : '';

const resumes = $input.all();

let combinedResumesText = '';
resumes.forEach((r, idx) => {
  combinedResumesText += `\n\n--- CANDIDATE RESUME ${idx + 1} ---\n${r.json.text || 'Error extracting text'}`;
});

const prompt = `You are an expert HR recruiter and resume analyst. Your job is to evaluate candidates fairly and identify the best potential matches.

**DYNAMIC JOB REQUIREMENTS:**
- **Position:** ${jd.role_title || 'Software Engineer'}
- **Required Skills:** ${skillsText}
- **Experience Level:** ${jd.experience_level || 'Not Specified'}
- **Include Coding Assessment:** ${jd.include_coding ? 'Yes' : 'No'}${jobDescContext}

**CANDIDATE RESUMES TO ANALYZE:**
${combinedResumesText}

**SCORING INSTRUCTIONS:**
For EACH candidate, extract and analyze:
1. Basic info (name, email, phone, location).
2. Professional background (current title, company, experience years).
3. Skills match against required skills.
4. **Match Score (1-100)** using this calibration:

   **Score Calibration Guide:**
   - 85-100: Strong match — has most required skills + relevant experience
   - 70-84: Good match — has several required skills or strong transferable skills
   - 50-69: Partial match — has some overlap or adjacent technology experience
   - 30-49: Weak match — minimal skill overlap but has general dev experience
   - 0-29: Poor match — no relevant skills or experience

   **Scoring Weights:**
   - Required Skills match (50%): Direct or closely related technology experience (e.g. Express.js counts for Node.js, MySQL counts partially for PostgreSQL)
   - Transferable/Adjacent Skills (25%): Related frameworks, languages, or tools that demonstrate adaptability
   - Experience & Trajectory (25%): Years of experience, project complexity, career growth, education

   **IMPORTANT:** Be generous with transferable skills. A React developer has JavaScript knowledge relevant to Node.js. A developer using any SQL database has skills transferable to PostgreSQL. Score the POTENTIAL, not just exact keyword matches.

**CRITICAL OUTPUT REQUIREMENTS:**
Evaluate EVERY candidate provided above. You must return your analysis strictly as an object containing a \"candidates\" array matching the structured output tool schema. Include detailed key_strengths, concerns, and reasoning in ai_analysis.`;

return {
  json: {
    aiPrompt: prompt,
    job_id: jd.id,
    role_title: jd.role_title || 'Software Engineer',
    skills: skillsText,
    experience_level: jd.experience_level || 'Not Specified',
    jid: jd.jid || null,
    include_coding: jd.include_coding || false,
    mcq_time_limit: jd.mcq_time_limit || 30
  }
};

const data = $input.first().json;
console.log('=== RAW AI OUTPUT KEYS ===', Object.keys(data));

// The chainLlm + StructuredOutputParser can return data in multiple formats:
// 1. data.text (raw text with JSON/markdown)
// 2. data.output (structured object or string)
// 3. data.candidates (directly parsed)
// 4. data directly IS the parsed object

let candidates = [];

// Strategy 1: Direct candidates array
if (data.candidates && Array.isArray(data.candidates)) {
  console.log('Found candidates directly in data.candidates');
  candidates = data.candidates;
}
// Strategy 2: Nested in output object
else if (data.output) {
  let outputData = data.output;
  if (typeof outputData === 'string') {
    try {
      const cleaned = outputData.replace(/```(?:json)?([\s\S]*?)```/, '$1').trim();
      outputData = JSON.parse(cleaned);
    } catch(e) { console.log('Failed to parse output string'); }
  }
  if (outputData && outputData.candidates) {
    candidates = outputData.candidates;
    console.log('Found candidates in data.output.candidates');
  } else if (Array.isArray(outputData)) {
    candidates = outputData;
    console.log('data.output is array of candidates');
  }
}
// Strategy 3: Raw text with JSON
else if (data.text) {
  let rawText = data.text;
  const jsonMatch = rawText.match(/```(?:json)?([\s\S]*?)```/);
  if (jsonMatch && jsonMatch[1]) rawText = jsonMatch[1].trim();
  try {
    const parsed = JSON.parse(rawText);
    candidates = parsed.candidates || (Array.isArray(parsed) ? parsed : []);
    console.log('Parsed candidates from text field');
  } catch(e) {
    console.log('Failed to parse text field');
  }
}

if (!Array.isArray(candidates)) candidates = [candidates];
candidates = candidates.filter(c => c && c.name);

console.log(`=== EXTRACTED ${candidates.length} CANDIDATES ===`);
candidates.forEach((c, i) => {
  console.log(`  ${i+1}. ${c.name} | score: ${c.match_score} | email: ${c.email}`);
});

// Get job context from earlier node
const promptData = $('Prepare Dynamic AI Prompt').first().json;

return candidates.map(candidate => {
  // Explicitly extract and cast match_score to integer
  let score = candidate.match_score || candidate.matchScore || candidate.score || 0;
  if (typeof score === 'string') score = parseInt(score, 10);
  score = Math.round(score);

  return {
    json: {
      name: candidate.name || 'Unknown',
      email: candidate.email || '',
      phone: candidate.phone || '',
      location: candidate.location || '',
      current_company: candidate.current_company || candidate.currentCompany || '',
      job_title: candidate.job_title || candidate.current_title || '',
      experience_years: candidate.experience_years || candidate.experienceYears || 0,
      match_score: score,
      skills: candidate.skills || [],
      ai_analysis: candidate.ai_analysis || candidate.aiAnalysis || {},
      screening_id: 'scr_' + Date.now() + '_' + Math.random().toString(36).substr(2, 5),
      role_title: promptData.role_title || 'Software Engineer',
      jid: promptData.jid || null
    }
  };
});

// AUTOMATED: Process Candidates & Generate MCQ Questions
// Bypasses HR Form - automatically generates MCQs for top candidates from AI Resume Matcher

const candidateItems = $input.all();

// Get job requirements from earlier in the workflow
let jobRequirements = {};
try {
  const jdNodes = $('Fetch Job Description').all();
  if (jdNodes.length > 0) {
    jobRequirements = jdNodes[0].json;
  }
} catch (error) {
  console.log('Could not get job requirements from DB');
}

// Extract configuration from JD or use defaults
// Assumes focus_areas is stored in DB. If not, fallback to Comprehensive
let focusAreas = ['Comprehensive Assessment (All Areas)'];
try {
  if (jobRequirements.skills) {
    focusAreas = Array.isArray(jobRequirements.skills) ? jobRequirements.skills : [jobRequirements.skills];
  }
} catch (e) {}

const assessmentType = ['Standard MCQ Assessment']; // Automated default
const questionPoolSize = jobRequirements.question_count || 5;
const questionsPerCandidate = Math.min(3, questionPoolSize); // Example: 3 questions per candidate

console.log('Focus Areas:', focusAreas);
console.log(`Pool Size: ${questionPoolSize}, Per Candidate: ${questionsPerCandidate}`);

// Process candidates
const selectedCandidates = candidateItems.map((item, index) => {
  const c = item.json;

  // Use the screening_id generated by Convert AI Output to Items
  const screeningId = c.screening_id || `screening_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

  return {
    id: `candidate_${index + 1}`,
    name: c.name || 'Unknown',
    email: c.email || 'no-email@example.com',
    phone: c.phone || '',
    location: c.location || '',
    currentCompany: c.current_company || '',
    jobTitle: c.job_title || jobRequirements.job_title || '',
    experienceYears: c.experience_years || 0,
    skills: c.skills || [],
    matchScore: c.match_score || 0,
    aiAnalysis: c.ai_analysis || {},

    screeningId: screeningId,
    linkExpiration: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString(),
    assessmentStatus: 'invited',
    invitedAt: new Date().toISOString()
  };
});

console.log(`Processing ${selectedCandidates.length} automatically selected candidates`);

const includeCoding = assessmentType.some(type => type.includes('coding challenge'));
const focusOnTechStack = assessmentType.some(type => type.includes('technology stack'));

// Survey questions (Empty for automated flow unless pulled from DB)
const surveyQuestions = [];

const generateMCQPrompt = () => {
  const jobTitle = jobRequirements.role_title || jobRequirements.job_title || 'Software Engineer';
  const requiredSkills = jobRequirements.skills ? jobRequirements.skills.join(', ') : 'Programming skills';
  const optionalSkills = jobRequirements.optional_skills || 'None';
  const experienceLevel = jobRequirements.experience_level || '2-5 years';

  return `You are an expert Technical Assessment Designer. Create ${questionPoolSize} multiple-choice questions for a Round 0 AI Screening assessment QUESTION POOL.

**JOB CONTEXT:**
- **Position:** ${jobTitle}
- **Experience Level:** ${experienceLevel}
- **Required Skills:** ${requiredSkills}

**ASSESSMENT FOCUS AREAS:**
${focusAreas.join(', ')}

**⭐ QUESTION POOL REQUIREMENTS:**
- **Total Pool Size:** ${questionPoolSize} questions
- **Question Types:** Multiple choice (4 options each)
- **Difficulty:** Adjust based on ${experienceLevel} experience level
- **Include Coding:** ${includeCoding ? 'Yes' : 'No'}

**OUTPUT FORMAT:**
Return a JSON object with this exact structure:
{
  "assessmentMetadata": {
    "jobTitle": "${jobTitle}",
    "estimatedDuration": "15 minutes",
    "difficulty": "intermediate"
  },
  "questions": [
    {
      "id": 1,
      "category": "Technical Skills",
      "difficulty": "medium",
      "question": "What is...",
      "options": { "A": "...", "B": "...", "C": "...", "D": "..." },
      "correctAnswer": "A",
      "explanation": "Because...",
      "timeLimit": 90
    }
  ]
}

Ensure valid JSON output ONLY.`;
};

const mcqPrompt = generateMCQPrompt();

const screeningLinks = selectedCandidates.map(candidate => ({
  candidateId: candidate.screeningId,
  candidateName: candidate.name,
  candidateEmail: candidate.email,
  screeningUrl: `http://localhost:5173/candidate/selfie-verification?id=${candidate.screeningId}`,
  expiresAt: candidate.linkExpiration,
  generatedAt: new Date().toISOString()
}));

const emailTasks = selectedCandidates.map((candidate, index) => {
  const screeningLink = screeningLinks[index];

  return {
    to: candidate.email,
    candidateName: candidate.name,
    subject: `Technical Assessment Invitation - ${jobRequirements.role_title || 'Position'}`,
    emailBody: `
    <div style="font-family: Arial, sans-serif; padding: 20px;">
      <h2>🎯 Assessment Invitation</h2>
      <p>Dear ${candidate.name},</p>
      <p>Based on your resume match (Score: ${candidate.matchScore}/100) for the <strong>${jobRequirements.role_title || 'Position'}</strong> role, you have been invited to complete a technical assessment.</p>
      <p>Please click the link below to verify your identity and begin:</p>
      <a href="${screeningLink.screeningUrl}" style="background: #007bff; color: white; padding: 10px 20px; text-decoration: none; border-radius: 5px;">Start Assessment</a>
      <p>This link expires on ${new Date(candidate.linkExpiration).toLocaleDateString()}.</p>
    </div>`,
    screeningId: candidate.screeningId
  };
});

return [{
  json: {
    mcqPrompt: mcqPrompt,
    selectedCandidates: selectedCandidates,
    candidateCount: selectedCandidates.length,
    surveyQuestions: surveyQuestions,
    jobRequirements: jobRequirements,
    emailTasks: emailTasks,
    assessmentConfig: {
      questionPoolSize: questionPoolSize,
      questionsPerCandidate: questionsPerCandidate,
      estimatedDuration: 15
    }
  }
}];

// Parse MCQ Output & Prepare Email Data - FIXED VERSION
const mcqResponse = $input.first().json;
const mcqGenerationData = $('Process Selections & Generate MCQ').first().json;

// Extract MCQ questions from AI response
let mcqQuestions = [];
let assessmentMetadata = {};

try {
  const outputText = mcqResponse.output;
  const cleanedOutput = outputText.replace(/```json\n|\n```|```/g, '').trim();
  const parsedMCQ = JSON.parse(cleanedOutput);

  mcqQuestions = parsedMCQ.questions || [];
  assessmentMetadata = parsedMCQ.assessmentMetadata || {};

  console.log(`Successfully parsed ${mcqQuestions.length} MCQ questions`);

} catch (error) {
  console.log('Error parsing MCQ JSON:', error.message);
  return [{
    json: {
      error: 'Failed to parse MCQ questions',
      details: error.message,
      rawOutput: mcqResponse.output
    }
  }];
}

const emailTasks = mcqGenerationData.emailTasks || [];
const selectedCandidates = mcqGenerationData.selectedCandidates || [];

const enhancedEmailTasks = emailTasks.map((emailTask, index) => {

  const matchingCandidate = selectedCandidates.find(c => c.email === emailTask.to);
  const screeningId = matchingCandidate?.screeningId || emailTask.screeningId;

  // ✅ ENHANCED: More aggressive removal of all instruction blocks
  let updatedBody = emailTask.emailBody;
  // Remove all variations of Important Instructions blocks
  updatedBody = updatedBody.replace(/⚠️\s*Important Instructions[\s\S]*?(?=🔗|<a href|Assessment ID:|<\/div>\s*<\/div>)/gi, '');
  // Remove Two-Stage Assessment Process blocks
  updatedBody = updatedBody.replace(/📋\s*Two-Stage Assessment Process[\s\S]*?(?=🔗|<a href|Assessment ID:|<\/div>\s*<\/div>)/gi, '');
  // Remove any orphaned instruction list items or divs
  updatedBody = updatedBody.replace(/<div[^>]*>\s*<h3[^>]*>⚠️[^<]*Important Instructions[^<]*<\/h3>[\s\S]*?<\/div>/gi, '');
  updatedBody = updatedBody.replace(/<div[^>]*>\s*<h3[^>]*>📋[^<]*Two-Stage[^<]*<\/h3>[\s\S]*?<\/div>/gi, '');
  // Remove Proctoring line
  updatedBody = updatedBody.replace(/<li>\s*<strong>Proctoring:<\/strong>.*?<\/li>/gi, '');
  updatedBody = updatedBody.replace(/•?\s*Proctoring:.*?Camera monitoring enabled for technical round\s*/gi, '');
  // Clean up multiple line breaks
  updatedBody = updatedBody.replace(/\n{3,}/g, '\n\n');
  updatedBody = updatedBody.trim();

  // Build fresh instructions block with proper bullet points in HTML
  const instructionsBlock = `
<div style="background: #e7f3ff; border: 2px solid #007bff; border-radius: 8px; padding: 20px; margin-bottom: 20px;">
<h3 style="margin: 0 0 15px 0; color: #0066cc;">⚠️ Important Instructions</h3>
<ul style="margin: 0; padding-left: 20px; color: #495057; line-height: 1.8;">
<li><strong>Two-Stage Process:</strong> Complete preference screening first, then technical assessment</li>
<li><strong>Qualifying Questions:</strong> Must be passed to unlock technical exam</li>
<li><strong>Camera Required:</strong> Ensure your camera works for the technical round</li>
<li><strong>Stable Internet:</strong> Use a reliable internet connection</li>
<li><strong>Quiet Environment:</strong> Choose a distraction-free location</li>
<li><strong>No External Help:</strong> Assessment must be completed independently</li>
<li><strong>Single Attempt:</strong> You can only take this assessment once</li>
<li><strong>Time Limit:</strong> Complete within 3 days of receiving this email</li>
</ul>
</div>
`;

  // Insert instructions ONLY above the link section - try multiple markers
  if (updatedBody.includes('🔗 Your Assessment Link')) {
    updatedBody = updatedBody.replace('🔗 Your Assessment Link', `${instructionsBlock}\n🔗 Your Assessment Link`);
  } else if (updatedBody.includes('<h3')) {
    // If no link marker found, insert before the first remaining h3 tag that contains 🔗
    updatedBody = updatedBody.replace(/(<h3[^>]*>🔗)/i, `${instructionsBlock}\n$1`);
  } else if (updatedBody.includes('Start Two-Stage Assessment')) {
    updatedBody = updatedBody.replace('Start Two-Stage Assessment', `${instructionsBlock}\n\nStart Two-Stage Assessment`);
  }

  return {
    ...emailTask,
    screeningId,
    enhancedEmailBody: updatedBody
      .replace('Approximately 30 minutes', assessmentMetadata.estimatedDuration || '30 minutes')
      .replace('Multiple Choice Questions (MCQ)', `${mcqQuestions.length} Multiple Choice Questions (MCQ)`),

    mcqData: {
      questionCount: mcqQuestions.length,
      assessmentMetadata,
      estimatedDuration: assessmentMetadata.estimatedDuration || '30 minutes',
      difficulty: assessmentMetadata.difficulty || 'intermediate'
    },

    emailMetadata: {
      hasValidMCQ: mcqQuestions.length > 0,
      questionCount: mcqQuestions.length,
      candidateName: emailTask.candidateName,
      candidateEmail: emailTask.to,
      screeningId,
      readyToSend: true
    }
  };
});

const assessmentData = {
  assessmentId: `assessment_${Date.now()}`,
  jobTitle: assessmentMetadata.jobTitle || 'Data Scientist',
  createdAt: new Date().toISOString(),
  expiresAt: selectedCandidates[0]?.linkExpiration || new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString(),

  metadata: assessmentMetadata,
  questions: mcqQuestions,

  candidates: selectedCandidates.map(candidate => ({
    screeningId: candidate.screeningId,
    name: candidate.name,
    email: candidate.email,
    status: 'invited',
    invitedAt: candidate.invitedAt,
    linkExpiration: candidate.linkExpiration
  })),

  configuration: {
    questionCount: mcqQuestions.length,
    timeLimit: assessmentMetadata.estimatedDuration || '30 minutes',
    proctoring: true,
    singleAttempt: true,
    antiCheating: true
  }
};

return [{
  json: {
    emailTasks: enhancedEmailTasks,
    emailCount: enhancedEmailTasks.length,
    mcqQuestions,
    assessmentMetadata,
    assessmentData,
    success: mcqQuestions.length > 0 && enhancedEmailTasks.length > 0,
    readyForEmailSending: true
  }
}];

const emailData = $input.all();
console.log('=== PREPARING GENERATED MCQs FOR DATABASE ===');

let mcqQuestions = [];
let assessmentMetadata = {};
let emailTasks = [];
let selectedCandidates = [];

try {
  const mcqData = $('Parse MCQ & Prepare Emails').first().json;
  mcqQuestions = mcqData.mcqQuestions || [];
  assessmentMetadata = mcqData.assessmentMetadata || {};
  emailTasks = mcqData.emailTasks || [];

  const selectionData = $('Process Selections & Generate MCQ').first().json;
  selectedCandidates = selectionData.selectedCandidates || [];
} catch (error) {
  console.error('Error getting MCQ data:', error.message);
}

const questionsData = [];

emailTasks.forEach((emailTask) => {
  const screeningId = emailTask.screeningId;
  const targetQuestions = mcqQuestions.slice(0, 3); // 3 per candidate

  targetQuestions.forEach((question, qIndex) => {
    questionsData.push({
      screening_id: screeningId,
      question_id: question.id || qIndex + 1,
      question_text: question.question || `Question ${qIndex + 1}`,
      options: JSON.stringify(question.options || {}),
      correct_answer: question.correctAnswer || 'A',
      category: question.category || 'General',
      difficulty: question.difficulty || 'medium',
      explanation: question.explanation || '',
      time_limit: question.timeLimit || 90
    });
  });
});

return [{
  json: {
    summary: "Prepared MCQs for Database Insertion",
    questionsData: questionsData
  }
}];
